// Return the calmest sailing window (lowest combined wind + gust) in the
// upcoming forecast for a position. Delegates coord validation to the shared
// helper and reuses fetchWeather; the window-finding itself lives in the pure
// computeBestWindow function so this handler stays thin.
async function getBestWindow(c: any) {
  return functions.call('withValidatedCoords', c, async (lat: number, lon: number) => {
    // Reuse the shared weather fetch (Result pattern)
    const result = await functions.call('fetchWeather', lat, lon);

    // Map a fetch failure to a 500 with the underlying message
    if (!result.ok) {
      return c.json({ error: true, message: result.error.message }, 500);
    }

    const weatherData = result.data;

    // Read tunable window/horizon from config (fall back to sensible defaults)
    const windowHours = config.get('BEST_WINDOW_SIZE_HOURS') || 3;
    const horizonHours = config.get('BEST_WINDOW_HORIZON_HOURS') || 24;

    // Compute the calmest window over the hourly forecast
    const window = functions.call('computeBestWindow', weatherData.hourly, windowHours, horizonHours);

    // Defensive: should not happen since fetchWeather returns 48h of data
    if (!window) {
      return c.json({ error: true, message: 'Not enough forecast data to determine a sailing window' }, 500);
    }

    // Echo position/timezone alongside the window for client display
    return c.json({
      latitude: weatherData.latitude,
      longitude: weatherData.longitude,
      timezone: weatherData.timezone,
      window
    });
  }, 'Failed to compute best sailing window');
}
